13	  for (const [x, y] of liveCells) {
14	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
15	      const neighbor: Cell = [x + dx, y + dy];
16	      const k = cellKey(neighbor);
17	      const entry = counts.get(k);
18	      counts.set(k, { cell: neighbor, count: (entry?.count ?? 0) + 1 });
19	    }
20	  }
21	  return counts;
22	};
23	
