25	  const liveSet = new Set(liveCells.map(cellKey));
26	  const neighborCounts = countNeighbors(liveCells);
27	
28	  const survives = (k: string, count: number): boolean =>
29	    count === 3 || (count === 2 && liveSet.has(k));
30	
31	  return [...neighborCounts]
32	    .filter(([k, { count }]) => survives(k, count))
