const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveSet = new Set(liveCells.map(cellKey));
  const candidates = new Map<string, Cell>();
  const neighborCounts = new Map<string, number>();

  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = cellKey(neighbor);
      candidates.set(k, neighbor);
      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
    }
  }

  const survivesOrBorn = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && liveSet.has(k));

  return [...candidates]
    .filter(([k]) => survivesOrBorn(k, neighborCounts.get(k) ?? 0))
    .map(([, cell]) => cell);
};

